ALTER TABLE "process_instances" ADD CONSTRAINT "process_instances_lifecycle_bundle" CHECK ((((status)::text = 'completed'::text) AND (completed_at IS NOT NULL)) OR (((status)::text = ANY ((ARRAY['active'::character varying, 'blocked'::character varying])::text[])) AND (completed_at IS NULL))), ADD CONSTRAINT "process_instances_status_allowed" CHECK ((status)::text = ANY ((ARRAY['active'::character varying, 'completed'::character varying, 'blocked'::character varying])::text[]));
