-- Modify "process_node_instances" table
ALTER TABLE "process_node_instances" ADD CONSTRAINT "process_node_instances_lifecycle_bundle" CHECK ((((status)::text = 'waiting'::text) AND (started_at IS NULL) AND (completed_at IS NULL)) OR (((status)::text = 'active'::text) AND (started_at IS NOT NULL) AND (completed_at IS NULL)) OR (((status)::text = 'completed'::text) AND (started_at IS NOT NULL) AND (completed_at IS NOT NULL)) OR (((status)::text = 'blocked'::text) AND (started_at IS NOT NULL) AND (completed_at IS NULL))), ADD CONSTRAINT "process_node_instances_status_allowed" CHECK ((status)::text = ANY ((ARRAY['waiting'::character varying, 'active'::character varying, 'completed'::character varying, 'blocked'::character varying])::text[])), ADD CONSTRAINT "process_node_instances_type_allowed" CHECK ((node_type)::text = ANY ((ARRAY['human_task'::character varying, 'approval'::character varying, 'domain_command'::character varying, 'wait_event'::character varying, 'end'::character varying])::text[])), ADD CONSTRAINT "process_node_instances_version_positive" CHECK (version > 0);
-- Modify "workflow_tasks" table
ALTER TABLE "workflow_tasks" ADD CONSTRAINT "workflow_tasks_process_anchors_paired" CHECK (((process_instance_id IS NULL) AND (process_node_instance_id IS NULL)) OR ((process_instance_id IS NOT NULL) AND (process_node_instance_id IS NOT NULL))), ADD CONSTRAINT "workflow_tasks_status_allowed" CHECK ((task_status_key)::text = ANY ((ARRAY['ready'::character varying, 'blocked'::character varying, 'done'::character varying, 'rejected'::character varying])::text[])), ADD CONSTRAINT "workflow_tasks_urge_count_non_negative" CHECK (urge_count >= 0), ADD CONSTRAINT "workflow_tasks_version_positive" CHECK (version > 0), DROP COLUMN "started_at", DROP COLUMN "closed_at", ADD COLUMN "critical_path" boolean NOT NULL DEFAULT false, ADD COLUMN "urge_count" bigint NOT NULL DEFAULT 0, ADD COLUMN "last_urged_at" timestamptz NULL, ADD COLUMN "last_urged_by" bigint NULL, ADD COLUMN "last_urged_by_role_key" character varying NULL, ADD COLUMN "escalated_at" timestamptz NULL, ADD COLUMN "escalate_target_role_key" character varying NULL, ADD CONSTRAINT "workflow_tasks_process_instances_workflow_tasks" FOREIGN KEY ("process_instance_id") REFERENCES "process_instances" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION, ADD CONSTRAINT "workflow_tasks_process_node_instances_workflow_tasks" FOREIGN KEY ("process_node_instance_id") REFERENCES "process_node_instances" ("id") ON UPDATE NO ACTION ON DELETE NO ACTION;
